module top_module(
    A,
    B,
    C,
    D,
    X
);// Module ports
    input A;
    input B;
    input C;
    input D;
    output X;

    // Local signals
    wire invalid_nor;
    wire and_out;

    //  Name  Output      Other arguments
    nor nor_gate (invalid_nor, A, B);
    and and_gate (and_out, C, D);
    assign X = invalid_nor & and_out;

endmodule
